    internal static readonly UdmTypeId Int32 = new(0xD664116E3EF90155, 0xF95398A47E4C82F4); // { 0x55, 0x01, 0xF9, 0x3E, 0x6E, 0x11, 0x64, 0xD6, 0xF4, 0x82, 0x4C, 0x7E, 0xA4, 0x98, 0x53, 0xF9 };
    internal static readonly UdmTypeId UInt32 = new(0x6FFE27D39D702F6F, 0x965AE53BD68C7FFB); // { 0x6F, 0x2F, 0x70, 0x9D, 0xD3, 0x27, 0xFE, 0x6F, 0xFB, 0x7F, 0x8C, 0xD6, 0x3B, 0xE5, 0x5A, 0x96 };
    internal static readonly UdmTypeId Int64 = new(0x8F87B13F683E546B, 0x7007E4269C6B8444); // { 0x6B, 0x54, 0x3E, 0x68, 0x3F, 0xB1, 0x87, 0x8F, 0x44, 0x84, 0x6B, 0x9C, 0x26, 0xE4, 0x07, 0x70 };
    internal static readonly UdmTypeId UInt64 = new(0x279710C1E4B3A899, 0x410D5C4789D9A419); // { 0x99, 0xA8, 0xB3, 0xE4, 0xC1, 0x10, 0x97, 0x27, 0x19, 0xA4, 0xD9, 0x89, 0x47, 0x5C, 0x0D, 0x41 };
    internal static readonly UdmTypeId Float = new(0x4A5DED29EF6657EF, 0xA6CA0334C3604AAE); // { 0xEF, 0x57, 0x66, 0xEF, 0x29, 0xED, 0x5D, 0x4A, 0xAE, 0x4A, 0x60, 0xC3, 0x34, 0x03, 0xCA, 0xA6 };
