    internal static readonly UdmTypeId Hash = new(0x3090EB64C2A77086, 0xE97BF47CF068450F); // { 0x86, 0x70, 0xA7, 0xC2, 0x64, 0xEB, 0x90, 0x30, 0x0F, 0x45, 0x68, 0xF0, 0x7C, 0xF4, 0x7B, 0xE9 };
    internal static readonly UdmTypeId Guid = new(0x94936E5BD1D3669A, 0x02C4E210F24CA7BD); // { 0x9A, 0x66, 0xD3, 0xD1, 0x5B, 0x6E, 0x93, 0x94, 0xBD, 0xA7, 0x4C, 0xF2, 0x10, 0xE2, 0xC4, 0x02 };
    internal static readonly UdmTypeId Reference = new(0x7857ADC6A4AAF0F9, 0x510EC867E443B28C); // { 0xF9, 0xF0, 0xAA, 0xA4, 0xC6, 0xAD, 0x57, 0x78, 0x8C, 0xB2, 0x43, 0xE4, 0x67, 0xC8, 0x0E, 0x51 };
    internal static readonly UdmTypeId Utf8String = new(0xDB8CB7A7413E6560, 0x3392C689B41663DD); // { 0x60, 0x65, 0x3E, 0x41, 0xA7, 0xB7, 0x8C, 0xDB, 0xDD, 0x63, 0x16, 0xB4, 0x89, 0xC6, 0x92, 0x33 };

    internal Hash hash;

    internal UdmTypeId(ulong Uint64Data1, ulong Uint64Data2) => (hash.Uint64Data1, hash.Uint64Data2) = (Uint64Data1, Uint64Data2);
    internal UdmTypeId(Hash hashValue) => hash = hashValue;

    public override bool Equals(object? obj) => (obj is UdmTypeId other) ? hash.Equals(other.hash) : false;
    public bool Equals(UdmTypeId other) => hash.Equals(other.hash);
    public override int GetHashCode() => hash.GetHashCode();
    public static bool operator ==(UdmTypeId left, UdmTypeId right) => left.hash == right.hash;
    public static bool operator !=(UdmTypeId left, UdmTypeId right) => left.hash != right.hash;

    internal static UdmTypeId HashString(string str)
    {
        var bytes = Encoding.UTF8.GetBytes(str);
        return HashBytes(bytes);
    }

    internal static UdmTypeId HashBytes(byte[] bytes)
    {
        //TODO: Once Nuget packages are supported
        // comment this back in
        //var xxHash = XxHash128.Hash(bytes);
        //var uint64Data1 = BitConverter.ToUInt64(xxHash, 0);
        //var uint64Data2 = BitConverter.ToUInt64(xxHash, 8);
        
        var str = Convert.ToBase64String(bytes);
        var hash = (uint) str.GetHashCode();
        return new UdmTypeId(hash, hash);
    }

    internal readonly bool IsValid() => hash.IsValid();

    internal string ToHex() => hash.ToHex();

    internal static UdmTypeId FromHex(string hex) => new UdmTypeId() { hash = DataModel.Hash.FromHex(hex) };
}

#nullable restore
